def get_phase(phase: int) -> dict:
    for item in PHASE_REGISTRY:
        if item["phase"] == phase:
            return dict(item)
    raise KeyError(f"Unknown phase: {phase}")


def list_phases() -> list[dict]:
    return [dict(item) for item in PHASE_REGISTRY]


def phase_metadata_summary(phase: int) -> dict:
    item = get_phase(phase)
    return {
        "phase": item["phase"],
        "phase_id": item["phase_id"],
        "title": item["title"],
        "domain": item["domain"],
        "layer": item["layer"],
        "module_count": item["module_count"],
        "maturity": item["maturity"]["level"],
        "boundary": item["boundary"],
        "project_identity": item.get("project_identity", {}),
        "standards_profile": item.get("standards_profile", {}),
    }
